	id := total_ship + jj
	bestRecord := trialRecord{assignIdx: -1, pos: -1, costDelta: 1e18, success: false}
	savedStates := make([]Assign, dispatch.AssignsLen)
	for ii := 0; ii < dispatch.AssignsLen; ii++ {
		savedStates[ii] = dispatch.Assigns[ii]
	}
	originalCosts := make([]float64, dispatch.AssignsLen)
	for ii := 0; ii < dispatch.AssignsLen; ii++ {
		originalCosts[ii] = dispatch.Assigns[ii].Cost
	}
	for ii := 0; ii <= dispatch.AssignsLen; ii++ {
		idx := ii
		if idx == dispatch.AssignsLen {
			if dispatch.AssignsLen < MAXASSIGNS {
				testAssign := Assign{}
				if testAssign.AddShip(id, ori, des) {
					testAssign.GenRoute()
					newCost := testAssign.Cost
					if newCost >= 0 {
						score := newCost * 0.8 + cal_dis(testAssign.StationCurrent, ori)*0.2
						if score < bestRecord.costDelta {
							bestRecord.assignIdx = idx
							bestRecord.pos = 0
							bestRecord.costDelta = score
