		for attemptPos := 0; attemptPos < 3; attemptPos++ {
			*currentAssign = savedBeforeTrial
			if currentAssign.AddShip(id, ori, des) {
				currentAssign.GenRoute()
				newCost := currentAssign.Cost
				if newCost >= 0 && originalCosts[idx] >= 0 {
